let payload = msg.payload;
if (typeof payload === "string") {
    try {
        payload = JSON.parse(payload);
    } catch (error) {
        node.warn(`Invalid Sparkplug payload: ${error.message}`);
        return null;
    }
}
msg.payload = payload;
return msg;

const source = msg.payload || {};
const metricValues = {};
for (const metric of source.metrics || []) {
    metricValues[metric.name] = metric.value;
}
const values = Object.assign({}, metricValues, source.values || {});
const topic = "uns/CO326/Plant1/Line1/MotorCell/Motor01/telemetry";
msg.topic = topic;
msg.payload = JSON.stringify({
    timestamp: source.timestamp || Date.now(),
    namespace: "UNS",
    unsPath: topic,
    sourceNamespace: source.namespace || "spBv1.0",
    sourceTopic: "spBv1.0/CO326/DDATA/Plant1.Line1.MotorCell/Motor01",
    useCase: source.use_case || "Motor overheating monitoring with relay trip simulation",
    groupId: source.group_id || "CO326",
    edgeNodeId: source.edge_node_id || "Plant1.Line1.MotorCell",
    deviceId: source.device_id || "Motor01",
    values: {
        motorTemperatureC: values.motorTemperatureC ?? values["Motor/WindingTemperature"],
        relayCommand: values.relayCommand ?? values["Relay/CommandedState"],
        relayFeedback: values.relayFeedback ?? values["Relay/FeedbackState"],
        motorState: values.motorState ?? values["Motor/RunState"],
        tripReason: values.tripReason ?? values["Motor/TripReason"],
        overTemperature: values.overTemperature ?? values["Motor/OverTemperature"]
    }
});
return msg;

const source = msg.payload || {};
const metricValues = {};
for (const metric of source.metrics || []) {
    metricValues[metric.name] = metric.value;
}
const values = Object.assign({}, metricValues, source.values || {});
const temperature = Number(values.motorTemperatureC ?? values["Motor/WindingTemperature"]);
const relayFeedback = String(values.relayFeedback ?? values["Relay/FeedbackState"] ?? "UNKNOWN").toUpperCase();
const lastTripAt = context.get("lastTripAt") || 0;
const now = Date.now();
if (!Number.isFinite(temperature) || temperature < 85 || relayFeedback === "OPEN" || now - lastTripAt < 10000) {
    return null;
}
context.set("lastTripAt", now);
msg.topic = "spBv1.0/CO326/DCMD/Plant1.Line1.MotorCell/Motor01";
msg.payload = JSON.stringify({
    timestamp: now,
    namespace: "spBv1.0",
    group_id: "CO326",
    edge_node_id: "Plant1.Line1.MotorCell",
    device_id: "Motor01",
    command: "TRIP",
    requested_by: "node-red-overtemp-interlock",
    reason: "NODE_RED_OVER_TEMP_INTERLOCK",
    metrics: [
        {
            name: "Relay/Command",
            datatype: "String",
            value: "TRIP",
            timestamp: now
        }
    ]
});
return msg;
